<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Version Diff Viewer</title>
  <style>
    html, body {
      margin: 0;
      padding: 0;
      height: 100%;
      width: 100%;
      background: #1e1e2f;
      color: #ffffff;
      font-family: "Segoe UI", Roboto, sans-serif;
    }

    #version-heading {
      text-align: center;
      padding: 12px 0;
      background: #2b2b3d;
      font-size: 17px;
      font-weight: 600;
      border-bottom: 1px solid #3a3a4d;
      letter-spacing: 0.3px;
    }

    #version-heading span {
      color: #7dcfff;
    }

    #diff-container {
      height: calc(100% - 50px);
      width: 100%;
    }
  </style>
  <script src="https://cdnjs.cloudflare.com/ajax/libs/require.js/2.3.6/require.min.js"></script>
</head>
<body>
  <div id="version-heading">
    Version Difference for <span>{{ comp_name }}</span><br/>
    Comparing <span>Version {{ curr_version }}</span> → <span>Version {{ sel_version }}</span>
  </div>

  <div id="diff-container"></div>

  <script>
    const lhs = {{ lhs_output | default("") | tojson }};
    const rhs = {{ rhs_output | default("") | tojson }};

    window.require.config({
      paths: {
        vs: "https://cdn.jsdelivr.net/npm/monaco-editor@0.45.0/min/vs"
      }
    });

    window.require(["vs/editor/editor.main"], function () {
      const container = document.getElementById("diff-container");

      if (!lhs || !rhs) {
        container.innerHTML = "<div style='padding: 20px; text-align: center;'>";
        container.innerHTML += "<h3>Unable to load version data</h3>";
        container.innerHTML += "<p>Please ensure both versions exist in the registry.</p>";
        container.innerHTML += "<p>Component: {{ comp_name }}<br/>";
        container.innerHTML += "Current Version: {{ curr_version }}<br/>";
        container.innerHTML += "Compare Version: {{ sel_version }}</p>";
        container.innerHTML += "</div>";
        return;
      }

      const originalModel = monaco.editor.createModel(lhs, "text/plain");
      const modifiedModel = monaco.editor.createModel(rhs, "text/plain");

      monaco.editor.createDiffEditor(container, {
        theme: "vs-dark",
        readOnly: true,
        enableSplitViewResizing: true,
        automaticLayout: true
      }).setModel({
        original: originalModel,
        modified: modifiedModel
      });
    });
  </script>
</body>
</html>

